0.query:
timeseries dequeue_cnt = avg(ibmmq.queue.dequeue_cnt), by: { low_q_depth_limit, service_interval, device.address, queue_type, max_queue_depth, dt.metrics.source, description, `dt.entity.ibmmq:local_queue`, connection_name_list, backout_threshold, queue_monitoring, queue_name, connected_host, trigger_control, queue_manager, backout_requeue_name, queue_usage, actual_qm_name, high_q_depth_limit, trigger_depth, `dt.entity.ibmmq:queue_manager` }
| fieldsAdd dequeue_rate = dequeue_cnt[] / 60
| summarize { dequeue_rate = avg(dequeue_rate[] ) }, by: { `dt.entity.ibmmq:local_queue`, timeframe, interval }
| sort arrayAvg(dequeue_rate) desc
| limit 20

